import base64
from pathlib import Path
ROOT = Path(__file__).parent
p = ROOT / "src/hyprag/chunker.py"
p.parent.mkdir(parents=True, exist_ok=True)
p.write_bytes(base64.b64decode(""))
print("[+] src/hyprag/chunker.py updated with rich text extraction")
print()
print("What changed:")
print("  Before: chunk text = raw source code (noisy)")
print("  After:  chunk text = node_path + signature + docstring (signal-rich)")
print()
print("Example - asyncio.base_events.BaseEventLoop.call_soon now reads:")
print("  asyncio.base_events.BaseEventLoop.call_soon")
print("  def call_soon(self, callback, *args, context=None):")
print("  Arrange for a callback to be called as soon as possible...")
print()
print("Now run the benchmark:")
print("  set PYTHONPATH=src;.")
print("  python benchmarks\\run_benchmark.py --cpython-lib cpython\\Lib --encoder BAAI/bge-base-en-v1.5")
